void swap(int* a, int* b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}
int main() {
    int x, y;
    if (cin >> x >> y) {
        swap(&x, &y);
        cout << x << " " << y << endl;
    }
    return 0;
}

